    15→package term
    16→
    17→import (
    18→	"bufio"
    19→	"bytes"
    20→	"io"
    21→	"math"
    22→	"strings"
    23→
    24→	"github.com/unstablebuild/rune-go-sdk/term/graphemecluster"
    25→)
    26→
    27→// CellsToString returns the string representation of the given cell matrix.
    28→func CellsToString(cells [][]Cell) string {
    29→	builder := strings.Builder{}
    30→	CellsToStringBuilder(&builder, cells)
    31→	return builder.String()
    32→}
    33→
    34→// CellsToStringBuilder copies the string representation of the given cell matrix
    35→// to the supplied builder.
    36→//
    37→// Caller is responsible for resetting builder prior to this call if necessary.
    38→func CellsToStringBuilder(builder *strings.Builder, cells [][]Cell) {
    39→	copyToBuilder(builder, cells)
    40→}
    41→
    42→// CellsToBytesBuffer copies the bytes representation of the given cell matrix
    43→// to the supplied buffer.
    44→//
    45→// Caller is responsible for resetting buffer prior to this call if necessary.
    46→func CellsToBytesBuffer(buffer *bytes.Buffer, cells [][]Cell) {
    47→	copyToBuffer(buffer, cells)
    48→}
    49→
    50→// StringToCells returns the cell matrix representation of the given string.
    51→func StringToCells(str string) (cells [][]Cell) {
    52→	var builder rawCells
    53→	builder.init()
    54→	_, _ = builder.ReadFrom(strings.NewReader(str))
    55→	return builder.cells
    56→}
    57→
    58→// CloneCells returns a deep clone of in.
    59→func CloneCells(in [][]Cell) [][]Cell {
    60→	ret := make([][]Cell, len(in))
    61→	for i, r := range in {
    62→		ret[i] = make([]Cell, len(r))
    63→		copy(ret[i], r)
    64→	}
    65→	return ret
    66→}
    67→
    68→// CopyCells copies src into dst, re-using dst's capacity when possible.
    69→func CopyCells(dst [][]Cell, src [][]Cell) [][]Cell {
    70→	if len(dst) > len(src) {
    71→		dst = dst[:len(src)]
    72→	} else if len(dst) < len(src) {
    73→		for i := len(dst); i < len(src); i++ {
    74→			dst = append(dst, nil) // will be replaced with a proper row below
    75→		}
    76→	}
    77→
    78→	for i := range len(src) {
    79→		if cap(dst[i]) < len(src[i]) {
    80→			dst[i] = make([]Cell, len(src[i]))
    81→		} else if dst[i] == nil { // cap=0, len=0; set to nil above
    82→			dst[i] = make([]Cell, 0)
    83→		} else {
    84→			dst[i] = dst[i][:len(src[i])]
    85→		}
    86→		copy(dst[i], src[i])
    87→	}
    88→	return dst
    89→}
    90→
    91→// CalculateOptimalWidth calculates the width of this cells,
    92→// such that nothing is truncated if rendered.
    93→func CalculateOptimalWidth(cells [][]Cell) (max int) {
    94→	for _, row := range cells {
    95→		var rowcount int
    96→		for _, c := range row {
    97→			rowcount += int(c.Width)
    98→		}
    99→		if rowcount > max {
   100→			max = rowcount
   101→		}
   102→	}
   103→	return
   104→}
   105→
   106→func nextWrite(c [][]Cell) Coordinates {
   107→	y := len(c) - 1
   108→	x := len(c[y])
   109→	return Coordinates{X: x, Y: y}
   110→}
   111→
   112→func copyToBuilder(builder *strings.Builder, cells [][]Cell) {
   113→	for i, r := range cells {
   114→		if i != 0 {
   115→			builder.WriteByte('\n')
   116→		}
   117→		copyRowToBuilder(builder, r)
   118→	}
   119→}
   120→
   121→func copyRowToBuilder(builder *strings.Builder, cells []Cell) {
   122→	builder.Grow(len(cells)) // almost every time this is exact
   123→	for _, c := range cells {
   124→		builder.WriteRune(c.Ch)
   125→		for _, comb := range c.Combining {
   126→			builder.WriteRune(comb)
   127→		}
   128→	}
   129→}
   130→
   131→func copyToBuffer(builder *bytes.Buffer, cells [][]Cell) {
   132→	for i, r := range cells {
   133→		if i != 0 {
   134→			builder.WriteByte('\n')
   135→		}
   136→		copyRowToBuffer(builder, r)
   137→	}
   138→}
