package fileexplorer

import (
	"path/filepath"
	"slices"
	"strings"

	"github.com/unstablebuild/rune-go-sdk/api/workspaceapi"
	"github.com/unstablebuild/rune-go-sdk/term"
)

type node struct {
	name     string
	uri      workspaceapi.URI
	isDir    bool
	expanded bool
	depth    int
	parent   *node
	children []*node
}

type parsedEntry struct {
	name  string
	isDir bool
	depth int
}

func readChildren(
	fs workspaceapi.FileSystem, n *node,
) error {
	entries, err := fs.ReadDir(n.uri.Path())
	if err != nil {
		return err
	}
	children := make([]*node, 0, len(entries))
	for _, e := range entries {
		child := &node{
			name:   e.Name(),
			uri:    workspaceapi.Join(n.uri, e.Name()),
			isDir:  e.IsDir(),
			depth:  n.depth + 1,
			parent: n,
		}
		children = append(children, child)
	}
	sortChildren(children)
	n.children = children
	return nil
}

func sortChildren(children []*node) {
	slices.SortFunc(children, func(a, b *node) int {
		if a.isDir != b.isDir {
			if a.isDir {
				return -1
			}
			return 1
		}
		return strings.Compare(a.name, b.name)
	})
}

func flatten(root *node) []*node {
	var flat []*node
	var walk func(n *node)
	walk = func(n *node) {
		for _, child := range n.children {
			flat = append(flat, child)
			if child.isDir && child.expanded {
				walk(child)
			}
		}
	}
	walk(root)
	return flat
}

func renderCells(
	flat []*node, cfg Config,
) [][]term.Cell {
	rows := make([][]term.Cell, 0, len(flat))
	for _, n := range flat {
		line := renderLine(n, cfg)
		rows = append(rows, term.StringToCells(line)...)
	}
	return rows
}

func renderLine(n *node, cfg Config) string {
	var b strings.Builder
	indent := indentRune(cfg)
	for range n.depth {
		b.WriteRune(indent)
		b.WriteRune(' ')
	}
	b.WriteRune(iconFor(n, cfg))
	b.WriteRune(' ')
	b.WriteString(n.name)
	if n.isDir {
		b.WriteRune('/')
	}
	return b.String()
}

func indentRune(cfg Config) rune {
	if cfg.IndentRune != 0 {
		return cfg.IndentRune
	}
	return '│'
}

func iconFor(n *node, cfg Config) rune {
	if cfg.Icons == nil {
		return ' '
	}
	if n.isDir {
		if icon, ok := cfg.Icons["/"]; ok {
			return icon
		}
	} else {
		ext := filepath.Ext(n.name)
		if icon, ok := cfg.Icons[ext]; ok {
			return icon
		}
	}
	if icon, ok := cfg.Icons[""]; ok {
		return icon
	}
	return ' '
}

func parseCells(
	cells [][]term.Cell, cfg Config,
) []parsedEntry {
	entries := make([]parsedEntry, 0, len(cells))
	indent := indentRune(cfg)
	for _, row := range cells {
		line := cellsToRowString(row)
		entry := parseLine(line, indent)
		entries = append(entries, entry)
	}
	return entries
}

func cellsToRowString(row []term.Cell) string {
	var b strings.Builder
	for _, c := range row {
		b.WriteRune(c.Ch)
		for _, comb := range c.Combining {
			b.WriteRune(comb)
		}
	}
	return b.String()
}

func parseLine(line string, indent rune) parsedEntry {
	var depth int
	runes := []rune(line)
	i := 0
	for i+1 < len(runes) &&
		runes[i] == indent && runes[i+1] == ' ' {
		depth++
		i += 2
	}
	// skip icon + space
	if i+1 < len(runes) {
		i += 2
	}
	name := string(runes[i:])
	isDir := strings.HasSuffix(name, "/")
	if isDir {
		name = strings.TrimSuffix(name, "/")
	}
	return parsedEntry{
		name:  name,
		isDir: isDir,
		depth: depth,
	}
}

func collectExpandedPaths(root *node) map[string]bool {
	expanded := make(map[string]bool)
	var walk func(n *node)
	walk = func(n *node) {
		for _, child := range n.children {
			if child.isDir && child.expanded {
				expanded[child.uri.String()] = true
				walk(child)
			}
		}
	}
	walk(root)
	return expanded
}

func restoreExpanded(
	fs workspaceapi.FileSystem,
	root *node,
	expanded map[string]bool,
) error {
	for _, child := range root.children {
		if !child.isDir {
			continue
		}
		if !expanded[child.uri.String()] {
			continue
		}
		if err := readChildren(fs, child); err != nil {
			return err
		}
		child.expanded = true
		if err := restoreExpanded(fs, child, expanded); err != nil {
			return err
		}
	}
	return nil
}

