			{name: "z.go", isDir: false},
			{name: "a.go", isDir: false},
			{name: "m", isDir: true},
			{name: "b", isDir: true},
		},
		"/project/m": {},
		"/project/b": {},
	}}
	c, err := New(mfs, rootURI())
	require.NoError(t, err)

	expected := strings.Join([]string{
