		"  m/",
		"  a.go",
		"  z.go",
	}, "\n")
	assert.Equal(t, expected, cellsString(c.Cells()))
}

func TestNestedExpansion(t *testing.T) {
	mfs := &mockFS{dirs: map[string][]mockEntry{
		"/project": {
			{name: "src", isDir: true},
		},
		"/project/src": {
			{name: "handlers", isDir: true},
			{name: "main.go", isDir: false},
		},
		"/project/src/handlers": {
			{name: "auth.go", isDir: false},
		},
	}}
	c, err := New(mfs, rootURI())
	require.NoError(t, err)

	// expand src
	c.ExpandNodeAt(term.Coordinates{Y: 0})
	// expand handlers (now at row 1)
	c.ExpandNodeAt(term.Coordinates{Y: 1})

	expected := strings.Join([]string{
		"  src/",
		"│   handlers/",
		"│ │   auth.go",
		"│   main.go",
	}, "\n")
	assert.Equal(t, expected, cellsString(c.Cells()))
}

func TestChangesNone(t *testing.T) {
	mfs := &mockFS{dirs: map[string][]mockEntry{
		"/project": {
			{name: "main.go", isDir: false},
		},
	}}
	c, err := New(mfs, rootURI())
	require.NoError(t, err)

	ops := c.Changes()
	assert.Empty(t, ops)
}

func TestChangesCreateFile(t *testing.T) {
	mfs := &mockFS{dirs: map[string][]mockEntry{
		"/project": {
			{name: "main.go", isDir: false},
		},
	}}
	c, err := New(mfs, rootURI())
	require.NoError(t, err)

	cells := c.Cells()
	newRow := term.StringToCells("  new.go")
	cells = append(cells, newRow...)
	c.SetCells(cells)

	ops := c.Changes()
	require.Len(t, ops, 1)
	assert.Equal(t, OpCreate, ops[0].Type)
	assert.Equal(t,
		"file:///project/new.go",
		ops[0].NewURI.String(),
	)
}

func TestChangesCreateDirectory(t *testing.T) {
	mfs := &mockFS{dirs: map[string][]mockEntry{
		"/project": {
			{name: "main.go", isDir: false},
		},
	}}
	c, err := New(mfs, rootURI())
	require.NoError(t, err)

	cells := c.Cells()
	newRow := term.StringToCells("  newdir/")
	cells = append(cells, newRow...)
	c.SetCells(cells)

	ops := c.Changes()
	require.Len(t, ops, 1)
	assert.Equal(t, OpMkdir, ops[0].Type)
	assert.Equal(t,
		"file:///project/newdir",
		ops[0].NewURI.String(),
	)
}

func TestChangesDelete(t *testing.T) {
	mfs := &mockFS{dirs: map[string][]mockEntry{
		"/project": {
			{name: "a.go", isDir: false},
			{name: "b.go", isDir: false},
		},
	}}
	c, err := New(mfs, rootURI())
	require.NoError(t, err)

	// remove first row (a.go)
	cells := c.Cells()
	c.SetCells(cells[1:])

	ops := c.Changes()
	require.Len(t, ops, 1)
	assert.Equal(t, OpDelete, ops[0].Type)
	assert.Equal(t,
		"file:///project/a.go",
		ops[0].URI.String(),
	)
}

func TestChangesRename(t *testing.T) {
	mfs := &mockFS{dirs: map[string][]mockEntry{
		"/project": {
			{name: "old.go", isDir: false},
		},
	}}
	c, err := New(mfs, rootURI())
	require.NoError(t, err)

	newCells := term.StringToCells("  new.go")
	c.SetCells(newCells)

	ops := c.Changes()
	require.Len(t, ops, 1)
	assert.Equal(t, OpRename, ops[0].Type)
	assert.Equal(t,
		"file:///project/old.go",
		ops[0].URI.String(),
	)
	assert.Equal(t,
		"file:///project/new.go",
		ops[0].NewURI.String(),
	)
}

func TestChangesMultipleOps(t *testing.T) {
	mfs := &mockFS{dirs: map[string][]mockEntry{
		"/project": {
			{name: "a.go", isDir: false},
			{name: "b.go", isDir: false},
			{name: "c.go", isDir: false},
		},
	}}
	c, err := New(mfs, rootURI())
	require.NoError(t, err)

	// keep b.go, remove a.go and c.go, add d.go and dir/
	newCells := term.StringToCells(strings.Join(
		[]string{
			"  b.go",
			"  d.go",
			"  dir/",
		}, "\n"))
	c.SetCells(newCells)

	ops := c.Changes()
	assert.True(t, len(ops) >= 3, "expected >= 3 ops")
}

func TestSetCellsRoundtrip(t *testing.T) {
	mfs := &mockFS{dirs: map[string][]mockEntry{
		"/project": {
			{name: "main.go", isDir: false},
		},
	}}
	c, err := New(mfs, rootURI())
	require.NoError(t, err)

	original := cellsString(c.Cells())
	clone := term.CloneCells(c.Cells())
	c.SetCells(clone)
	assert.Equal(t, original, cellsString(c.Cells()))

	// draw after SetCells should not panic
	w := term.NewStringWriter(20, 5)
	c.Resize(20, 5)
	c.Draw(w)
}

func TestCustomIcons(t *testing.T) {
	mfs := &mockFS{dirs: map[string][]mockEntry{
		"/project": {
			{name: "src", isDir: true},
			{name: "main.go", isDir: false},
		},
		"/project/src": {},
	}}
	cfg := Config{
		Icons: map[string]rune{
			"/":   '',
			".go": '',
		},
	}
	c, err := NewWithConfig(mfs, rootURI(), cfg)
	require.NoError(t, err)

	expected := strings.Join([]string{
		"\uf07b src/",
		"\ue627 main.go",
	}, "\n")
	assert.Equal(t, expected, cellsString(c.Cells()))
}

func TestDefaultIndentRune(t *testing.T) {
	mfs := &mockFS{dirs: map[string][]mockEntry{
		"/project": {
			{name: "src", isDir: true},
		},
		"/project/src": {
			{name: "app.go", isDir: false},
		},
	}}
	c, err := NewWithConfig(
		mfs, rootURI(), Config{},
	)
	require.NoError(t, err)

	c.ExpandNodeAt(term.Coordinates{Y: 0})

	got := cellsString(c.Cells())
	assert.Contains(t, got, "│")
}

