    22→
    23→// Config defines options for the file explorer component.
    24→type Config struct {
    25→	// Icons maps file extensions to icon runes.
    26→	// "/" key is used for directories, "" for the default
    27→	// fallback icon.
    28→	Icons map[string]rune
    29→	// IndentRune is drawn for each depth level.
    30→	// Defaults to '│' (U+2502) when zero.
    31→	IndentRune rune
    32→}
    33→
    34→// Component renders a file tree. It implements
    35→// component.Floating and supports expand/collapse,
    36→// node lookup, external cell editing with change detection,
    37→// and filesystem reload.
    38→type Component struct {
    39→	fs     workspaceapi.FileSystem
    40→	root   workspaceapi.URI
    41→	cfg    Config
    42→	width  int
    43→	height int
    44→	cells  [][]term.Cell
    45→	tree   *node
    46→	flat   []*node
    47→}
    48→
    49→var _ component.Floating = (*Component)(nil)
    50→
    51→// New creates a new Component with the given fs, root URI and config.
    52→func New(
    53→	fs workspaceapi.FileSystem,
    54→	root workspaceapi.URI,
    55→	cfg Config,
    56→) (*Component, error) {
    57→	c := &Component{
    58→		fs:   fs,
    59→		root: root,
    60→		cfg:  cfg,
    61→		tree: &node{
    62→			uri:      root,
    63→			isDir:    true,
    64→			expanded: true,
    65→			depth:    -1,
    66→		},
    67→	}
    68→	if err := readChildren(fs, c.tree); err != nil {
    69→		return nil, err
    70→	}
    71→	c.rebuild()
    72→	return c, nil
    73→}
    74→
    75→// Resize stores clip dimensions for Draw.
    76→func (c *Component) Resize(width, height int) {
    77→	c.width, c.height = width, height
    78→}
    79→
    80→// Draw draws cells clipped to width/height.
    81→func (c *Component) Draw(w term.Writer) {
    82→	for y, row := range c.cells {
    83→		if y >= c.height {
    84→			break
    85→		}
    86→		var offset int
    87→		for x, cell := range row {
    88→			xi := x + offset
