)

func main() {
	root := flag.String("root", ".", "root directory to explore")
	flag.Parse()

	absRoot, err := workspaceapi.CurrentUserHostURI(*root)
	if err != nil {
		log.Fatalf("invalid root path: %v", err)
	}

