	case ev.Key == term.KeyArrowLeft,
		ev.Key == term.KeyArrowRight,
		ev.Key == term.KeyTab:
		d.promptYes = !d.promptYes
		return false, true

	case ev.Key == term.KeyEnter:
		d.showPrompt = false
		if d.promptYes {
