		d.promptYes = !d.promptYes
		return false, true

	case ev.Key == term.KeyEnter:
		d.showPrompt = false
		if d.promptYes {
			d.executeChanges()
		} else {
			d.status = "Cancelled"
		}
		return false, true

	case ev.Ch == 'y' || ev.Ch == 'Y':
		d.showPrompt = false
		d.executeChanges()
		return false, true

	case ev.Ch == 'n' || ev.Ch == 'N':
		d.showPrompt = false
		d.status = "Cancelled"
		return false, true
	}

	return false, false
}

