    15→package fileexplorer
    16→
    17→import (
    18→	"github.com/unstablebuild/rune-go-sdk/api/workspaceapi"
    19→)
    20→
    21→// OperationType describes the kind of filesystem operation.
    22→type OperationType int
    23→
    24→const (
    25→	// OpCreate indicates a new file should be created.
    26→	OpCreate OperationType = iota
    27→	// OpMkdir indicates a new directory should be created.
    28→	OpMkdir
    29→	// OpDelete indicates a file or directory should be deleted.
    30→	OpDelete
    31→	// OpRename indicates a file or directory should be renamed.
    32→	OpRename
    33→)
    34→
    35→// Operation represents a single filesystem change detected by
    36→// diffing the edited cell buffer against the internal tree.
    37→type Operation struct {
    38→	Type   OperationType
    39→	URI    workspaceapi.URI
    40→	NewURI workspaceapi.URI
    41→}
    42→
    43→func computeChanges(
    44→	oldRoot *node, entries []parsedEntry, cfg Config,
    45→) []Operation {
    46→	newTree := buildVirtualTree(entries)
    47→	var ops []Operation
    48→	diffChildren(oldRoot, newTree, cfg, &ops)
    49→	return ops
    50→}
    51→
    52→func buildVirtualTree(entries []parsedEntry) *node {
    53→	root := &node{depth: 0}
    54→	stack := []*node{root}
    55→	for _, e := range entries {
    56→		for len(stack) > 1 && stack[len(stack)-1].depth >= e.depth {
    57→			stack = stack[:len(stack)-1]
    58→		}
    59→		parent := stack[len(stack)-1]
    60→		child := &node{
    61→			name:  e.name,
    62→			isDir: e.isDir,
    63→			depth: e.depth,
    64→		}
    65→		parent.children = append(parent.children, child)
    66→		if e.isDir {
    67→			stack = append(stack, child)
    68→		}
    69→	}
    70→	return root
    71→}
    72→
    73→func diffChildren(
    74→	old, new *node, cfg Config, ops *[]Operation,
    75→) {
    76→	oldByName := make(map[string]*node, len(old.children))
    77→	for _, c := range old.children {
    78→		oldByName[c.name] = c
    79→	}
    80→	newByName := make(map[string]*node, len(new.children))
    81→	for _, c := range new.children {
    82→		newByName[c.name] = c
    83→	}
    84→
    85→	var removed []*node
    86→	var added []*node
    87→
    88→	for _, c := range old.children {
    89→		if _, ok := newByName[c.name]; !ok {
    90→			removed = append(removed, c)
    91→		}
    92→	}
    93→	for _, c := range new.children {
    94→		if _, ok := oldByName[c.name]; !ok {
    95→			added = append(added, c)
    96→		}
    97→	}
    98→
    99→	if len(removed) == 1 && len(added) == 1 {
   100→		*ops = append(*ops, Operation{
   101→			Type:   OpRename,
   102→			URI:    removed[0].uri,
   103→			NewURI: workspaceapi.Join(
   104→				old.uri, added[0].name,
   105→			),
   106→		})
   107→	} else {
   108→		for _, c := range removed {
   109→			*ops = append(*ops, Operation{
   110→				Type: OpDelete,
   111→				URI:  c.uri,
   112→			})
   113→		}
   114→		for _, c := range added {
   115→			if c.isDir {
   116→				*ops = append(*ops, Operation{
   117→					Type: OpMkdir,
   118→					NewURI: workspaceapi.Join(
   119→						old.uri, c.name,
   120→					),
   121→				})
   122→			} else {
   123→				*ops = append(*ops, Operation{
   124→					Type: OpCreate,
   125→					NewURI: workspaceapi.Join(
   126→						old.uri, c.name,
   127→					),
   128→				})
   129→			}
   130→		}
   131→	}
   132→
   133→	for _, oc := range old.children {
   134→		if !oc.expanded {
   135→			continue
   136→		}
   137→		nc, ok := newByName[oc.name]
   138→		if !ok {
   139→			continue
   140→		}
   141→		diffChildren(oc, nc, cfg, ops)
   142→	}
   143→}
