	mfs := &mockFS{dirs: map[string][]mockEntry{
		"/project": {
			{name: "a", isDir: true},
			{name: "b", isDir: true},
		},
		"/project/a": {
			{name: "a1.go", isDir: false},
		},
		"/project/b": {
