	tests := []struct {
		name   string
		dirs   map[string][]mockEntry
		expand []int
		cells  string
		ops    []expectedOp
	}{
		{
			name: "no changes",
			dirs: map[string][]mockEntry{
				"/project": {
					{name: "main.go", isDir: false},
				},
