			cells: `  main.go`,
		},
		{
			name: "no changes in expanded tree",
			dirs: map[string][]mockEntry{
				"/project": {
					{name: "src", isDir: true},
				},
				"/project/src": {
					{name: "main.go", isDir: false},
				},
			},
			expand: []int{0},
			cells: `  src/
│   main.go`,
		},
		{
			name: "create file",
			dirs: map[string][]mockEntry{
				"/project": {
					{name: "main.go", isDir: false},
				},
			},
			cells: `  main.go
  new.go`,
			ops: []expectedOp{
				{OpCreate, "", "file:///project/new.go"},
			},
		},
		{
			name: "create directory",
			dirs: map[string][]mockEntry{
				"/project": {
					{name: "main.go", isDir: false},
				},
			},
			cells: `  main.go
  newdir/`,
			ops: []expectedOp{
				{OpMkdir, "", "file:///project/newdir"},
