	panic("not implemented")
}

func (m *mockFS) MkdirAll(string, os.FileMode) error {
	panic("not implemented")
}

func rootURI() workspaceapi.URI {
	u, err := workspaceapi.ParseURI("file:///project")
	if err != nil {
		panic(err)
	}
	return u
}

