		expand []int
		cells  string
		ops    []expectedOp
	}{
		{
			name: "no changes",
			dirs: map[string][]mockEntry{
				"/project": {
					{name: "main.go", isDir: false},
				},
			},
			cells: `  main.go`,
		},
		{
			name: "no changes in expanded tree",
			dirs: map[string][]mockEntry{
				"/project": {
					{name: "src", isDir: true},
				},
				"/project/src": {
					{name: "main.go", isDir: false},
				},
			},
			expand: []int{0},
			cells: `  src/
│   main.go`,
		},
		{
			name: "create file",
